(function () {
  const SDK = window.__HERMES_PLUGIN_SDK__;
  const Registry = window.__HERMES_PLUGINS__;
  if (!SDK || !Registry) return;

  const React = SDK.React;
  const hooks = SDK.hooks;
  const ui = SDK.components;
  const fetchJSON = SDK.fetchJSON;
  const cn = SDK.utils.cn;

  const e = React.createElement;

  function api(path, options) {
    return fetchJSON(`/api/plugins/hermes-threshold${path}`, options || {});
  }

  function count(summary, key) {
    if (!summary) return 0;
    if (Object.prototype.hasOwnProperty.call(summary, key)) return summary[key] || 0;
    return (summary.counts && summary.counts[key]) || 0;
  }

  function shortText(value, fallback) {
    if (!value) return fallback;
    return String(value).length > 180 ? `${String(value).slice(0, 177)}...` : String(value);
  }

  function formatTime(value) {
    if (!value) return "unknown time";
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return String(value);
    return date.toLocaleString([], {
      month: "short",
      day: "numeric",
      hour: "numeric",
      minute: "2-digit",
    });
  }

  function groupKey(suggestion) {
    const payload = suggestion.payload || {};
    return [
      suggestion.title || "",
      suggestion.description || "",
      payload.surface || "",
      payload.risk_score || "",
    ].join("\n");
  }

  function fallbackDetail(group) {
    if (group.title === "Define autonomy action tiers") {
      return "Behavior-design note: decide which Hermes actions are silent reflection, draft-only, notifications, approval-required, or forbidden. It is not an executed change.";
    }
    return "No expanded detail was stored with this older draft.";
  }

  function fallbackWhyNow(group) {
    if (group.title === "Define autonomy action tiers") {
      return "Generated by the controlled-trial scheduler while testing the low-risk autonomy policy path.";
    }
    return "Created by a wake decision and left unsent for review.";
  }

  function groupSuggestions(suggestions) {
    const groups = new Map();
    for (const suggestion of suggestions) {
      const key = groupKey(suggestion);
      const current = groups.get(key) || {
        key,
        title: suggestion.title || suggestion.suggestion_id,
        description: suggestion.description || "",
        surface: (suggestion.payload && suggestion.payload.surface) || "draft",
        detail: suggestion.payload && suggestion.payload.detail,
        whyNow: suggestion.payload && suggestion.payload.why_now,
        acceptanceHint: suggestion.payload && suggestion.payload.acceptance_hint,
        dismissalHint: suggestion.payload && suggestion.payload.dismissal_hint,
        riskScore: suggestion.payload && suggestion.payload.risk_score,
        valueScore: suggestion.payload && suggestion.payload.value_score,
        noveltyScore: suggestion.payload && suggestion.payload.novelty_score,
        suggestions: [],
      };
      current.suggestions.push(suggestion);
      groups.set(key, current);
    }
    return Array.from(groups.values()).map((group) => {
      group.suggestions.sort((a, b) => String(b.created_at).localeCompare(String(a.created_at)));
      group.latest = group.suggestions[0];
      group.oldest = group.suggestions[group.suggestions.length - 1];
      return group;
    });
  }

  function recommendationFor(group) {
    if (group.suggestions.length > 1) {
      return {
        label: "Recommended: Dismiss group",
        tone: "secondary",
        reason: "This is repeated controlled-trial output, not separate things that need your attention.",
        approveEffect: group.acceptanceHint || "Approve newest keeps one copy as a useful behavior-design note.",
        dismissEffect: group.dismissalHint || "Dismiss group clears these repeated draft rows from the review queue.",
      };
    }
    return {
      label: "Review",
      tone: "outline",
      reason: "This is a single unsent draft from a wake decision.",
      approveEffect: group.acceptanceHint || "Approve keeps it for Hermes behavior work.",
      dismissEffect: group.dismissalHint || "Dismiss removes it from the review queue.",
    };
  }

  function Stat({ label, value }) {
    return e(
      "div",
      { className: "flex flex-col gap-1 border border-border p-3" },
      e("span", { className: "text-muted-foreground text-xs" }, label),
      e("span", { className: "font-courier text-2xl tabular-nums" }, value),
    );
  }

  function ActionButton({ children, disabled, onClick, variant }) {
    return e(
      ui.Button,
      {
        variant,
        disabled,
        onClick,
        className: cn(
          "inline-flex items-center justify-center gap-2 border border-border bg-background/40 px-4 py-2",
          "text-sm font-courier transition-colors hover:bg-foreground/10 cursor-pointer",
        ),
      },
      children,
    );
  }

  function ReviewGroup({ group, onApprove, onDismissGroup, busy }) {
    const latest = group.latest;
    const copyCount = group.suggestions.length;
    const title = group.title || latest.suggestion_id;
    const rationale = group.description || latest.description || "";
    const copyLabel = copyCount === 1 ? "1 draft" : `${copyCount} copies`;
    const recommendation = recommendationFor(group);
    const detail = group.detail || fallbackDetail(group);
    const whyNow = group.whyNow || fallbackWhyNow(group);
    return e(
      "div",
      { className: "border border-border p-3" },
      e(
        "div",
        { className: "flex flex-wrap items-start justify-between gap-6" },
        e(
          "div",
          { className: "flex min-w-0 flex-1 flex-col gap-3" },
          e(
            "div",
            { className: "flex flex-wrap items-center gap-2" },
            e("span", { className: "font-medium" }, title),
            e(ui.Badge, { variant: recommendation.tone }, recommendation.label),
            e(ui.Badge, { variant: "secondary" }, copyLabel),
            e(ui.Badge, { variant: "outline" }, group.surface),
          ),
          e(
            "p",
            { className: "text-sm" },
            recommendation.reason,
          ),
          e(
            "p",
            { className: "text-sm text-muted-foreground" },
            shortText(rationale, latest.suggestion_id),
          ),
          e(
            "div",
            { className: "grid gap-3 text-sm md:grid-cols-2" },
            e(
              "div",
              { className: "flex flex-col gap-1 border border-border p-3" },
              e("span", { className: "font-medium" }, "What this idea is"),
              e("span", { className: "text-muted-foreground text-xs" }, detail),
            ),
            e(
              "div",
              { className: "flex flex-col gap-1 border border-border p-3" },
              e("span", { className: "font-medium" }, "Why it appeared"),
              e("span", { className: "text-muted-foreground text-xs" }, whyNow),
            ),
          ),
          e(
            "div",
            { className: "border border-border p-3 text-xs text-muted-foreground" },
            `Grouped as the same idea because title, summary, surface, and risk score match. Latest cycle: ${latest.cycle_id}.`,
          ),
          e(
            "div",
            { className: "grid gap-2 text-xs text-muted-foreground md:grid-cols-3" },
            e("div", null, `Newest: ${formatTime(latest.created_at)}`),
            e("div", null, `Oldest: ${formatTime(group.oldest.created_at)}`),
            e("div", null, `Value ${group.valueScore || "?"} / Novelty ${group.noveltyScore || "?"} / Risk ${group.riskScore || "?"}`),
          ),
        ),
        e(
          "div",
          { className: "flex w-56 shrink-0 flex-col items-stretch gap-2" },
          e(ActionButton, {
            disabled: busy,
            onClick: () => onApprove(latest.suggestion_id),
          },
            "Approve newest",
          ),
          e("span", { className: "text-xs text-muted-foreground" }, recommendation.approveEffect),
          e(ActionButton, {
            variant: "outline",
            disabled: busy,
            onClick: () => onDismissGroup(group.suggestions.map((item) => item.suggestion_id)),
          },
            copyCount === 1 ? "Dismiss" : "Dismiss group",
          ),
          e("span", { className: "text-xs text-muted-foreground" }, recommendation.dismissEffect),
        ),
      ),
    );
  }

  function ThresholdPage() {
    const [summary, setSummary] = hooks.useState(null);
    const [suggestions, setSuggestions] = hooks.useState([]);
    const [loading, setLoading] = hooks.useState(true);
    const [busyId, setBusyId] = hooks.useState(null);
    const [error, setError] = hooks.useState("");

    const load = hooks.useCallback(async () => {
      setError("");
      setLoading(true);
      try {
        const nextSummary = await api("/summary");
        const nextSuggestions = await api("/suggestions?status=drafted&limit=25");
        setSummary(nextSummary);
        setSuggestions(nextSuggestions.suggestions || []);
      } catch (err) {
        setError(err && err.message ? err.message : "Unable to load Threshold data");
      } finally {
        setLoading(false);
      }
    }, []);

    hooks.useEffect(() => {
      load();
    }, [load]);

    async function review(id, action) {
      setBusyId(id);
      setError("");
      try {
        await api(`/suggestions/${encodeURIComponent(id)}/${action}`, { method: "POST" });
        await load();
      } catch (err) {
        setError(err && err.message ? err.message : `Unable to ${action} suggestion`);
      } finally {
        setBusyId(null);
      }
    }

    async function dismissGroup(ids) {
      setBusyId(ids.join(","));
      setError("");
      try {
        await api("/suggestions/batch-dismiss", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ suggestion_ids: ids }),
        });
        await load();
      } catch (err) {
        setError(err && err.message ? err.message : "Unable to dismiss suggestion group");
      } finally {
        setBusyId(null);
      }
    }

    const groups = groupSuggestions(suggestions);
    const duplicateCopies = suggestions.length - groups.length;
    const decisionLabel = groups.length === 1 ? "1 decision" : `${groups.length} decisions`;

    return e(
      "div",
      { className: "flex flex-col gap-6" },
      e(
        ui.Card,
        null,
        e(
          ui.CardHeader,
          null,
          e(
            "div",
            { className: "flex items-center gap-3" },
            e(ui.CardTitle, { className: "text-lg" }, "Hermes Threshold"),
            e(ui.Badge, { variant: "outline" }, "trial"),
          ),
        ),
        e(
          ui.CardContent,
          { className: "flex flex-col gap-4" },
          e(
            "p",
            { className: "text-sm text-muted-foreground" },
            "Controlled-trial wake drafts. Nothing here has been sent or executed. Most repeated controlled-trial groups should be dismissed; approve only when the idea itself is useful enough to keep as Hermes behavior work.",
          ),
          e(
            "div",
            { className: "flex items-center gap-3" },
            e(ActionButton, { onClick: load, disabled: loading }, loading ? "Refreshing..." : "Refresh"),
            error && e("span", { className: "text-sm font-courier text-muted-foreground" }, error),
          ),
        ),
      ),
      e(
        ui.Card,
        null,
        e(
          ui.CardHeader,
          null,
          e(
            "div",
            { className: "flex items-center gap-3" },
            e(ui.CardTitle, { className: "text-base" }, "Trial Counters"),
            e(ui.Badge, { variant: "outline" }, loading ? "loading" : "live"),
          ),
        ),
        e(
          ui.CardContent,
          null,
          e(
            "div",
            { className: "grid gap-3 text-sm md:grid-cols-5" },
            e(Stat, { label: "Wake cycles", value: count(summary, "wake_cycles") }),
            e(Stat, { label: "Drafts", value: count(summary, "drafted_suggestions") }),
            e(Stat, { label: "Approved", value: count(summary, "approved_suggestions") }),
            e(Stat, { label: "Dismissed", value: count(summary, "dismissed_suggestions") }),
            e(Stat, { label: "Useful", value: count(summary, "useful_feedback") }),
          ),
        ),
      ),
      e(
        ui.Card,
        null,
        e(
          ui.CardHeader,
          null,
          e(
            "div",
            { className: "flex items-center justify-between gap-3" },
            e(ui.CardTitle, { className: "text-base" }, "Review Queue"),
            e(
              "div",
              { className: "flex flex-wrap items-center justify-end gap-2" },
              duplicateCopies > 0 ? e(ui.Badge, { variant: "secondary" }, `${duplicateCopies} duplicate copies grouped`) : null,
              e(ui.Badge, { variant: "outline" }, decisionLabel),
            ),
          ),
        ),
        e(
          ui.CardContent,
          null,
          loading
            ? e("div", { className: "text-sm text-muted-foreground" }, "Loading suggestions...")
            : groups.length === 0
              ? e("div", { className: "text-sm text-muted-foreground" }, "No draft suggestions are waiting for review.")
              : e(
                  "div",
                  { className: "grid gap-3 text-sm" },
                  groups.map((group) =>
                    e(ReviewGroup, {
                      key: group.key,
                      group,
                      busy: group.suggestions.some((item) => busyId && busyId.includes(item.suggestion_id)),
                      onApprove: (id) => review(id, "approve"),
                      onDismissGroup: dismissGroup,
                    }),
                  ),
                ),
        ),
      ),
    );
  }

  Registry.register("hermes-threshold", ThresholdPage);
})();
